# data/rosters.py

def calculate_ovr(p):
    # Para leyendas, su OVR es directamente su potencial (pico de carrera)
    if p.get("is_legend", False):
        return p.get("pot", 90)
        
    s = p["s"]
    if p["pos"] == "GK":
        return s["gk"]
    
    # 6 Stats: speed, shot, passing, dribbling, defense, physical
    dri = s.get("dribbling", 75)
    phy = s.get("physical", 75)
    
    if p["pos"] in ["CB", "LB", "RB"]:
        # Defensas: Defensa es lo más importante
        return int(s["defense"] * 0.6 + phy * 0.2 + s["speed"] * 0.1 + s["passing"] * 0.1)
    elif p["pos"] == "CDM":
        # Mediocentros Defensivos: Defensa y Físico importan
        return int(s["defense"] * 0.4 + s["passing"] * 0.3 + phy * 0.2 + s["speed"] * 0.1)
    elif p["pos"] in ["CM", "CAM"]:
        # Medios: Pase y Regate dominan
        return int(s["passing"] * 0.5 + dri * 0.3 + s["speed"] * 0.1 + s["shot"] * 0.1)
    else: # ST, LW, RW
        # Delanteros: Tiro y Velocidad dominan
        return int(s["shot"] * 0.5 + s["speed"] * 0.25 + dri * 0.2 + s["passing"] * 0.05)

